const reestr_data = $('GetReestr').all();
const mintrud_data = $('GetMintrudFile').all();
const reestr_groups = [];

for (let reestr_stroke of reestr_data) {
  for (let rgs_data of reestr_stroke.json['Рег-номер (Выписка)'].split(',')) {
    let [group_name, reg_num] = rgs_data.split(':');

    const date_reestr =
      reestr_stroke.json["Дата окончания (фикс)"] ||
      reestr_stroke.json["Дата выдачи"] ||
      reestr_stroke.json["Дата создания"];

    let file_name = `ВЫПИСКА ${group_name} ${reestr_stroke.json["Компания"].replace('"','«').replace('"','»')} ${date_reestr.replaceAll('.','-')}`;

    reestr_groups.push({
      fio: reestr_stroke.json["Фамилия Имя Отчество"],
      file_name,
      date_reestr,
      group_name,
      reg_num,
      folder: reestr_stroke.json["ПАПКА"].split('/').slice(-1)[0]
    });
  }
}

// нормализация ФИО
const normalizeFio = (str) =>
  str.trim().toLowerCase().replace(/\s+/g, ' ');

// нормализация даты → dd.mm.yyyy
const normalizeDate = (str) => {
  if (!str) return '';
  return str.replace(/-/g, '.').trim();
};

// ключ для mintrud
const makeKeyFromMintrud = (item) => {
  const fio = `${item.json["Фамилия"]} ${item.json["Имя"]} ${item.json["Отчество"]}`;
  const date = normalizeDate(item.json["Дата проверки знаний"]);

  return `${normalizeFio(fio)}|${item.json["Номер протокола"]}|${date}`;
};

// ключ для reestr
const makeKeyFromReestr = (item) => {
  const date = normalizeDate(item.date_reestr);

  return `${normalizeFio(item.fio)}|${item.reg_num}|${date}`;
};

// map
const map = Object.fromEntries(
  mintrud_data.map(item => [makeKeyFromMintrud(item), item.json])
);

// объединение
const result = reestr_groups.map(item => {
  let match = map[makeKeyFromReestr(item)];

  // fallback без даты
  if (!match) {
    match = mintrud_data.find(d => {
      const fio = normalizeFio(
        `${d.json["Фамилия"]} ${d.json["Имя"]} ${d.json["Отчество"]}`
      );

      return (
        fio === normalizeFio(item.fio) &&
        d.json["Номер протокола"] === item.reg_num
      );
    })?.json;
  }

  return {
    json: {
      ...item,
      registry_number: match?.["Номер в реестре"] || null
    }
  };
});

return result;

const searchData = $('searchVyp').all();
const searchKey = $('Loop Over Items').first().json.file_name
let rs;

for (let searchResult of searchData) {
  if (searchResult.json.name.includes(searchKey)) {
    rs = [searchResult];
  }
};

if (rs) {
  return rs; 
} else {
  return [{}]
}

const doc = $input.first().json;
const content = doc.body.content;
const targetName = $('Loop Over Items').first().json.fio;
const num_in_mintrud_reestr = $('Loop Over Items').first().json.registry_number;

const table9 = content.find(el => el.table && el.table.columns === 9);
if (!table9) throw new Error("Таблица с 9 колонками не найдена");

for (const row of table9.table.tableRows) {
  const cells = row.tableCells;
  const nameText = cells[1]?.content
    ?.flatMap(p => p.paragraph?.elements ?? [])
    ?.map(e => e.textRun?.content ?? "")
    ?.join("")
    ?.trim();

  if (nameText === targetName) {
     return [{ json: { insertIndex: cells[6].content[0].startIndex, value: num_in_mintrud_reestr } }];;
  }
}

throw new Error(`ФИО "${targetName}" не найдено`);

